input.content:
{
  "name": "@node/periodic-table",
  "version": "1.0.0",
  "description": "Interactive periodic table explorer with element details, search, and category filtering",
  "modnet": {
    "contentType": "science",
    "structure": "collection",
    "mechanics": ["filter"],
    "boundary": "all",
    "scale": 3
  },
  "dependencies": {
    "@plaited/template": "latest"
  }
}

export type Element = {
  atomicNumber: number;
  symbol: string;
  name: string;
  atomicMass: number;
  category: string;
  electronConfiguration: string;
  oxidationStates: string;
  meltingPoint: number | null;
  boilingPoint: number | null;
  discoveryYear: number | null;
  description: string;
  row: number;
  col: number;
};

export type CategoryInfo = {
  label: string;
  color: string;
};

export type CategoryMap = Record<string, CategoryInfo>;

import type { CategoryMap } from './types';

export const CATEGORIES: CategoryMap = {
  'alkali-metal': { label: 'Alkali Metals', color: '#ff6b6b' },
  'alkaline-earth-metal': { label: 'Alkaline Earth Metals', color: '#ffa94d' },
  'transition-metal': { label: 'Transition Metals', color: '#74c0fc' },
  'post-transition-metal': { label: 'Post-transition Metals', color: '#69db7c' },
  'metalloid': { label: 'Metalloids', color: '#a9e34b' },
  'nonmetal': { label: 'Nonmetals', color: '#ffd43b' },
  'halogen': { label: 'Halogens', color: '#da77f2' },
  'noble-gas': { label: 'Noble Gases', color: '#e599f7' },
  'lanthanide': { label: 'Lanthanides', color: '#66d9e8' },
  'actinide': { label: 'Actinides', color: '#f783ac' },
  'unknown': { label: 'Unknown', color: '#ced4da' },
};

export const getCategoryColor = (category: string): string =>
  CATEGORIES[category]?.color ?? '#ced4da';

export const getCategoryLabel = (category: string): string =>
  CATEGORIES[category]?.label ?? 'Unknown';

import { h, Fragment } from '@plaited/template';
import type { Element } from './types';
import { CATEGORIES, getCategoryColor, getCategoryLabel } from './categories';

const styles = {
  page: {
    fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
    maxWidth: '1280px',
    margin: '0 auto',
    padding: '16px',
    backgroundColor: '#f8f9fa',
    minHeight: '100vh',
  },
  header: {
    textAlign: 'center' as const,
    marginBottom: '16px',
  },
  title: {
    fontSize: '28px',
    fontWeight: 'bold',
    color: '#212529',
    margin: '0 0 12px 0',
  },
  controls: {
    display: 'flex',
    gap: '12px',
    justifyContent: 'center',
    flexWrap: 'wrap' as const,
    marginBottom: '16px',
  },
  searchInput: {
    padding: '8px 14px',
    fontSize: '14px',
    border: '1px solid #ced4da',
    borderRadius: '6px',
    width: '240px',
    outline: 'none',
  },
  select: {
    padding: '8px 14px',
    fontSize: '14px',
    border: '1px solid #ced4da',
    borderRadius: '6px',
    backgroundColor: '#fff',
    cursor: 'pointer',
  },
  tableContainer: {
    overflowX: 'auto' as const,
    padding: '8px 0',
  },
  grid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(18, minmax(58px, 1fr))',
    gridTemplateRows: 'repeat(10, auto)',
    gap: '2px',
    minWidth: '1080px',
  },
  cell: {
    padding: '3px 2px',
    textAlign: 'center' as const,
    borderRadius: '4px',
    cursor: 'pointer',
    textDecoration: 'none',
    color: '#212529',
    border: '1px solid rgba(0,0,0,0.1)',
    transition: 'transform 0.1s, box-shadow 0.1s',
    minHeight: '58px',
    display: 'flex',
    flexDirection: 'column' as const,
    justifyContent: 'center',
    alignItems: 'center',
  },
  cellNumber: {
    fontSize: '9px',
    color: '#495057',
    lineHeight: '1',
  },
  cellSymbol: {
    fontSize: '16px',
    fontWeight: 'bold',
    lineHeight: '1.2',
  },
  cellName: {
    fontSize: '7px',
    lineHeight: '1',
    whiteSpace: 'nowrap' as const,
    overflow: 'hidden' as const,
    textOverflow: 'ellipsis' as const,
    maxWidth: '100%',
  },
  cellMass: {
    fontSize: '8px',
    color: '#6c757d',
    lineHeight: '1',
  },
  lanActLabel: {
    fontSize: '11px',
    color: '#6c757d',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
  },
  legend: {
    display: 'flex',
    flexWrap: 'wrap' as const,
    gap: '8px',
    justifyContent: 'center',
    margin: '12px 0',
  },
  legendItem: {
    display: 'flex',
    alignItems: 'center',
    gap: '4px',
    fontSize: '11px',
    color: '#495057',
  },
  legendSwatch: {
    width: '14px',
    height: '14px',
    borderRadius: '3px',
    border: '1px solid rgba(0,0,0,0.15)',
  },
  detail: {
    position: 'fixed' as const,
    top: '0',
    right: '0',
    width: '360px',
    height: '100vh',
    backgroundColor: '#fff',
    boxShadow: '-4px 0 20px rgba(0,0,0,0.15)',
    padding: '24px',
    overflowY: 'auto' as const,
    zIndex: '1000',
  },
  detailClose: {
    position: 'absolute' as const,
    top: '12px',
    right: '16px',
    fontSize: '24px',
    textDecoration: 'none',
    color: '#868e96',
    lineHeight: '1',
  },
  detailSymbol: {
    fontSize: '64px',
    fontWeight: 'bold',
    textAlign: 'center' as const,
    margin: '8px 0',
    padding: '16px',
    borderRadius: '12px',
    color: '#212529',
  },
  detailName: {
    fontSize: '24px',
    fontWeight: 'bold',
    textAlign: 'center' as const,
    margin: '0 0 4px 0',
    color: '#212529',
  },
  detailCategory: {
    fontSize: '13px',
    textAlign: 'center' as const,
    color: '#868e96',
    margin: '0 0 16px 0',
  },
  detailGrid: {
    display: 'grid',
    gridTemplateColumns: '1fr 1fr',
    gap: '12px',
    marginBottom: '16px',
  },
  detailCard: {
    backgroundColor: '#f8f9fa',
    borderRadius: '8px',
    padding: '10px',
  },
  detailLabel: {
    fontSize: '10px',
    color: '#868e96',
    textTransform: 'uppercase' as const,
    letterSpacing: '0.5px',
    margin: '0 0 2px 0',
  },
  detailValue: {
    fontSize: '14px',
    fontWeight: '600',
    color: '#212529',
    margin: '0',
  },
  detailDesc: {
    fontSize: '14px',
    lineHeight: '1.5',
    color: '#495057',
    borderTop: '1px solid #e9ecef',
    paddingTop: '12px',
    margin: '0',
  },
  detailElConfig: {
    backgroundColor: '#f8f9fa',
    borderRadius: '8px',
    padding: '10px',
    marginBottom: '12px',
  },
};

const renderSearchBar = (search: string, category: string) =>
  h('form', { method: 'GET', style: styles.controls },
    h('input', {
      type: 'text',
      name: 'search',
      placeholder: 'Search by name, symbol, or number...',
      value: search,
      style: styles.searchInput,
    }),
    h('select', { name: 'category', style: styles.select, onchange: 'this.form.submit()' },
      h('option', { value: 'all', ...(category === 'all' ? { selected: '' } : {}) }, 'All Categories'),
      ...Object.entries(CATEGORIES).map(([key, info]) =>
        h('option', { value: key, ...(category === key ? { selected: '' } : {}) }, info.label)
      ),
    ),
    h('button', {
      type: 'submit',
      style: {
        ...styles.select,
        backgroundColor: '#228be6',
        color: '#fff',
        border: 'none',
        fontWeight: '600',
      },
    }, 'Search'),
    ...(search || category !== 'all'
      ? [h('a', {
          href: '/',
          style: {
            ...styles.select,
            textDecoration: 'none',
            display: 'inline-flex',
            alignItems: 'center',
          },
        }, 'Clear')]
      : []),
  );

const renderLegend = () =>
  h('div', { style: styles.legend },
    ...Object.entries(CATEGORIES).map(([, info]) =>
      h('div', { style: styles.legendItem },
        h('div', { style: { ...styles.legendSwatch, backgroundColor: info.color } }),
        h('span', {}, info.label),
      )
    ),
  );

const renderElementCell = (
  el: Element,
  isHighlighted: boolean,
  selectedId: number | null,
  search: string,
  category: string,
) => {
  const bgColor = getCategoryColor(el.category);
  const isSelected = el.atomicNumber === selectedId;
  const queryParams = new URLSearchParams();
  queryParams.set('element', el.atomicNumber.toString());
  if (search) queryParams.set('search', search);
  if (category !== 'all') queryParams.set('category', category);

  return h('a', {
    href: `?${queryParams.toString()}`,
    style: {
      ...styles.cell,
      gridRow: el.row.toString(),
      gridColumn: el.col.toString(),
      backgroundColor: bgColor,
      opacity: isHighlighted ? '1' : '0.2',
      border: isSelected ? '2px solid #212529' : '1px solid rgba(0,0,0,0.1)',
      boxShadow: isSelected ? '0 0 0 2px rgba(33,37,41,0.3)' : 'none',
    },
  },
    h('div', { style: styles.cellNumber }, el.atomicNumber.toString()),
    h('div', { style: styles.cellSymbol }, el.symbol),
    h('div', { style: styles.cellName }, el.name),
    h('div', { style: styles.cellMass },
      el.atomicMass % 1 === 0
        ? `[${el.atomicMass}]`
        : el.atomicMass.toFixed(el.atomicMass >= 100 ? 1 : 2),
    ),
  );
};

const renderLanthanideActinideLabels = () =>
  h(Fragment, {},
    h('div', {
      style: {
        ...styles.lanActLabel,
        gridRow: '6',
        gridColumn: '3',
      },
    }, '57-71'),
    h('div', {
      style: {
        ...styles.lanActLabel,
        gridRow: '7',
        gridColumn: '3',
      },
    }, '89-103'),
  );

const renderGapRow = () =>
  h('div', {
    style: {
      gridRow: '8',
      gridColumn: '1 / span 18',
      height: '12px',
    },
  });

const renderDetailPanel = (el: Element, search: string, category: string) => {
  const queryParams = new URLSearchParams();
  if (search) queryParams.set('search', search);
  if (category !== 'all') queryParams.set('category', category);
  const closeHref = queryParams.toString() ? `?${queryParams.toString()}` : '/';

  const formatTemp = (temp: number | null, unit = '\u00B0C') =>
    temp !== null ? `${temp} ${unit}` : 'Unknown';

  return h('div', { style: styles.detail },
    h('a', { href: closeHref, style: styles.detailClose }, '\u00D7'),
    h('div', {
      style: {
        ...styles.detailSymbol,
        backgroundColor: getCategoryColor(el.category),
      },
    }, el.symbol),
    h('h2', { style: styles.detailName }, el.name),
    h('p', { style: styles.detailCategory }, getCategoryLabel(el.category)),
    h('div', { style: styles.detailGrid },
      h('div', { style: styles.detailCard },
        h('p', { style: styles.detailLabel }, 'Atomic Number'),
        h('p', { style: styles.detailValue }, el.atomicNumber.toString()),
      ),
      h('div', { style: styles.detailCard },
        h('p', { style: styles.detailLabel }, 'Atomic Mass'),
        h('p', { style: styles.detailValue },
          el.atomicMass % 1 === 0
            ? `[${el.atomicMass}]`
            : el.atomicMass.toFixed(4),
        ),
      ),
      h('div', { style: styles.detailCard },
        h('p', { style: styles.detailLabel }, 'Melting Point'),
        h('p', { style: styles.detailValue }, formatTemp(el.meltingPoint)),
      ),
      h('div', { style: styles.detailCard },
        h('p', { style: styles.detailLabel }, 'Boiling Point'),
        h('p', { style: styles.detailValue }, formatTemp(el.boilingPoint)),
      ),
      h('div', { style: styles.detailCard },
        h('p', { style: styles.detailLabel }, 'Discovery'),
        h('p', { style: styles.detailValue },
          el.discoveryYear ? el.discoveryYear.toString() : 'Ancient',
        ),
      ),
      h('div', { style: styles.detailCard },
        h('p', { style: styles.detailLabel }, 'Oxidation States'),
        h('p', { style: styles.detailValue }, el.oxidationStates),
      ),
    ),
    h('div', { style: styles.detailElConfig },
      h('p', { style: styles.detailLabel }, 'Electron Configuration'),
      h('p', { style: { ...styles.detailValue, fontSize: '13px' } }, el.electronConfiguration),
    ),
    h('p', { style: styles.detailDesc }, el.description),
  );
};

export const renderPage = (
  allElements: Element[],
  filteredSet: Set<number>,
  selected: Element | null,
  search: string,
  category: string,
) =>
  h('html', { lang: 'en' },
    h('head', {},
      h('meta', { charset: 'UTF-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
      h('title', {}, 'Periodic Table Explorer'),
      h('style', {},
        `*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        body { margin: 0; background: #f8f9fa; }
        a:hover .cell-inner, a:hover { transform: scale(1.05); z-index: 10; }
        @media (max-width: 768px) {
          .detail-panel { width: 100% !important; }
        }`,
      ),
    ),
    h('body', {},
      h('div', { style: styles.page },
        h('div', { style: styles.header },
          h('h1', { style: styles.title }, 'Periodic Table of Elements'),
        ),
        renderSearchBar(search, category),
        renderLegend(),
        h('div', { style: styles.tableContainer },
          h('div', { style: styles.grid },
            ...allElements.map(el =>
              renderElementCell(el, filteredSet.has(el.atomicNumber), selected?.atomicNumber ?? null, search, category)
            ),
            renderLanthanideActinideLabels(),
            renderGapRow(),
          ),
        ),
      ),
      ...(selected ? [renderDetailPanel(selected, search, category)] : []),
    ),
  );

import { createSSR } from '@plaited/template/ssr';
import type { Element } from './types';
import { renderPage } from './render';

const loadElements = async (): Promise<Element[]> => {
  const file = Bun.file(new URL('../data/elements.json', import.meta.url).pathname);
  return file.json();
};

let cachedElements: Element[] | null = null;

const getElements = async (): Promise<Element[]> => {
  if (!cachedElements) {
    cachedElements = await loadElements();
  }
  return cachedElements;
};

const filterElements = (
  elements: Element[],
  search: string,
  category: string,
): Set<number> => {
  const result = new Set<number>();
  const query = search.toLowerCase().trim();

  for (const el of elements) {
    const matchesSearch =
      !query ||
      el.name.toLowerCase().includes(query) ||
      el.symbol.toLowerCase().includes(query) ||
      el.atomicNumber.toString() === query;

    const matchesCategory =
      category === 'all' || el.category === category;

    if (matchesSearch && matchesCategory) {
      result.add(el.atomicNumber);
    }
  }

  return result;
};

const handler = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);

  if (url.pathname !== '/' && url.pathname !== '') {
    return new Response('Not Found', { status: 404 });
  }

  const search = url.searchParams.get('search') ?? '';
  const category = url.searchParams.get('category') ?? 'all';
  const elementParam = url.searchParams.get('element');
  const selectedId = elementParam ? parseInt(elementParam, 10) : null;

  const elements = await getElements();
  const filteredSet = filterElements(elements, search, category);
  const selected =
    selectedId !== null
      ? elements.find(el => el.atomicNumber === selectedId) ?? null
      : null;

  const template = renderPage(elements, filteredSet, selected, search, category);
  const ssr = createSSR();
  const html = ssr(template);

  return new Response(`<!DOCTYPE html>${html}`, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });
};

export default { fetch: handler };
